        this.$drop_icon = $(`<button class="btn-reset drop-icon hidden">`).html(frappe.utils.icon(drop_icon, "sm", "", "", "", "", stroke_color)).appendTo(sidebar_control);
        this.$drop_icon.removeClass("hidden");
